const incoming = $json.body && typeof $json.body === 'object' ? $json.body : $json;
const payload = incoming.data && typeof incoming.data === 'object' ? incoming.data : incoming;
const expectedSharedSecret = $env.ORDER_WEBHOOK_SHARED_SECRET || '';
const normalizedEmail = String(payload.customerEmail || payload.email || '').trim().toLowerCase();
const normalizedCustomerId = String(payload.customerId || '').trim();
const safeCustomerId = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(normalizedCustomerId)
  ? normalizedCustomerId
  : '00000000-0000-0000-0000-000000000000';
const safeEmail = normalizedEmail || '__missing_email__@local.invalid';
const hasName = Boolean(String(payload.name || '').trim());
const hasPhone = Boolean(String(payload.phone || '').trim());
const hasEmail = Boolean(normalizedEmail);
const hasDeliveryMethod = Boolean(String(payload.deliveryMethod || '').trim());
const cart = Array.isArray(payload.cart) ? payload.cart : [];
const hasCart = cart.length > 0;
const sharedSecretValid = !expectedSharedSecret || (Boolean(payload.sharedSecret) && payload.sharedSecret === expectedSharedSecret);
const isValid = hasName && hasPhone && hasEmail && hasDeliveryMethod && hasCart && sharedSecretValid;
const validationMessage = !sharedSecretValid
  ? 'Invalid shared secret'
  : (!hasName || !hasPhone || !hasEmail || !hasDeliveryMethod || !hasCart
      ? 'Invalid order payload'
      : 'ok');
const itemsText = cart
  .map((item) => {
    const qty = Number(item.qty || 0);
    const price = Number(item.price || 0);
    const lineTotal = qty * price;
    const grind = item.grindLabel ? ` (${item.grindLabel})` : '';
    return `- ${item.title || 'Item'} x${qty}${grind} = ${lineTotal} грн`;
  })
  .join('\n');
const totalLabel = payload.totalLabel || `${Number(payload.total || 0)} грн`;
const telegramText = [
  'Нове замовлення з сайту Odesa Coffee Roasters',
  '',
  `Клієнт: ${payload.name || '-'}`,
  `Email: ${payload.email || payload.customerEmail || '-'}`,
  `Телефон: ${payload.phone || '-'}`,
  `Місто: ${payload.city || '-'}`,
  `Доставка: ${payload.deliveryMethodLabel || payload.deliveryMethod || '-'}`,
  `Деталі доставки: ${payload.deliveryDetails || '-'}`,
  `Оплата: ${payload.paymentMethodLabel || payload.paymentMethod || '-'}`,
  `Сума: ${totalLabel}`,
  '',
  'Товари:',
  itemsText || '-',
  '',
  `Дата: ${payload.createdAt || new Date().toISOString()}`,
  `Джерело: ${payload.source || 'website'}`
].join('\n');

return [{
  json: {
    payload,
    cart,
    valid: isValid,
    sharedSecretValid,
    validationMessage,
    customerId: normalizedCustomerId || null,
    safeCustomerId,
    email: safeEmail,
    telegramText
  }
}];

const source = $('Validate Order').item.json;
const payload = source.payload;
const byCustomerId = $('Find Profile By Customer Id').first()?.json || [];
const byEmail = $('Find Profile By Email').first()?.json || [];
const customerFromId = Array.isArray(byCustomerId) && byCustomerId.length > 0 ? byCustomerId[0] : null;
const customerFromEmail = Array.isArray(byEmail) && byEmail.length > 0 ? byEmail[0] : null;
const resolvedCustomer = customerFromId || customerFromEmail;

return [{
  json: {
    payload,
    telegramText: source.telegramText,
    customerId: resolvedCustomer?.id || null,
    customerEmail: resolvedCustomer?.email || payload.customerEmail || payload.email || null
  }
}];

const payload = $('Resolve Customer').item.json.payload;
const telegramText = $('Resolve Customer').item.json.telegramText;
const orderResponse = $json;
const createdOrder = Array.isArray(orderResponse) ? orderResponse[0] : orderResponse;
const orderId = createdOrder?.id || null;
const orderNumber = createdOrder?.order_number || null;
const cart = Array.isArray(payload.cart) ? payload.cart : [];
const items = cart.map((item) => ({
  order_id: orderId,
  product_id: item.id || null,
  product_title: item.title || 'Item',
  category: item.category || null,
  quantity: Number(item.qty || 0),
  unit_price: Number(item.price || 0),
  grind_method: item.grindMethod || null,
  grind_label: item.grindLabel || null,
  raw_item: item,
}));

return [{
  json: {
    orderId,
    orderNumber,
    payload,
    telegramText: orderNumber ? `${telegramText}\nНомер замовлення: #${orderNumber}` : telegramText,
    items
  }
}];
